import React from "react";

import styles from "../styles/Buttons.module.css";

type ButtonVariant = "primary" | "secondary" | "danger";
type ButtonSize = "small" | "medium" | "large";

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: ButtonVariant;
  size?: ButtonSize;
  children: React.ReactNode;
}

export function Button({
  variant = "primary",
  size = "medium",
  className = "",
  children,
  ...props
}: ButtonProps) {
  const sizeClass = size === "small" ? styles.small : size === "large" ? styles.large : "";

  return (
    <button className={`${styles[variant]} ${sizeClass} ${className}`.trim()} {...props}>
      {children}
    </button>
  );
}

export default Button;

.primary {
  padding: 8px 16px;
  background: var(--interactive-primary-bg);
  color: var(--interactive-primary-fg);
  border: 1px solid var(--interactive-primary-border);
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: 0.875rem;
}

.primary:hover:not(:disabled) {
  background: var(--interactive-primary-bg-hover);
  border-color: var(--interactive-primary-border);
}

.secondary {
  padding: 8px 16px;
  background: var(--interactive-secondary-bg);
  color: var(--interactive-secondary-fg);
  border: 1px solid var(--interactive-secondary-border);
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: 0.875rem;
}

.secondary:hover:not(:disabled) {
  color: var(--interactive-secondary-fg);
  background: var(--interactive-secondary-bg-hover);
  border-color: var(--interactive-secondary-border-hover);
}

.toolbarButton {
  display: inline-flex;
  align-items: center;
  gap: 0.375rem;
  padding: 0.5rem 0.75rem;
  background: var(--interactive-secondary-bg);
  color: var(--interactive-secondary-fg);
  border: 1px solid var(--interactive-secondary-border);
  border-radius: 4px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-size: 0.875rem;
  font-weight: 500;
  white-space: nowrap;
}

.toolbarButton:hover:not(:disabled) {
  background: var(--interactive-primary-bg);
  border-color: var(--interactive-primary-border);
  color: var(--interactive-primary-fg);
}

.danger {
  padding: 8px 16px;
  background: var(--danger-bg);
  color: var(--danger);
  border: 1px solid var(--danger);
  border-radius: 6px;
  cursor: pointer;
  transition: all var(--transition-fast);
  font-family: var(--font-mono);
  font-weight: 600;
  font-size: 0.875rem;
}

.danger:hover:not(:disabled) {
  background: var(--danger);
  color: var(--text-on-accent);
}

.small {
  padding: 4px 10px;
  font-size: 0.75rem;
}

.large {
  padding: 12px 24px;
  font-size: 1rem;
}

.primary:disabled,
.secondary:disabled,
.toolbarButton:disabled,
.danger:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
